#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
int n,ans;
string p[205],s,tmp;
bool dp[200005];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	while(cin>>tmp)
	{
		if(tmp==".") break;
		p[++n]=tmp;
	}
	while(cin>>tmp) s+=tmp;
	s=" "+s;
	dp[0]=1;
	for(int i=1;i<s.size();i++)
	{
		for(int j=1;j<=n;j++)
		{
			int t=p[j].size();
			if(i>=t&&dp[i-t]&&(p[j]==s.substr(i-t+1,t)))
			{
				ans=i;
				dp[i]=1;
				break;
			}
		}
        // cout<<dp[i]<<" ";
	}
	cout<<ans;
	return 0;
}
